import s from"./BseheQjt.js";import{_ as e}from"./suY7Nf0t.js";import{u as v}from"./CPLiJhAq.js";import{d,c as l,b as r,f as o,u as c,o as n,_ as p}from"./BZpGQicP.js";import"./_WVvNYDM.js";import"./DjTPuVMR.js";import"./WaCZesZL.js";import"./Bp3YSIOJ.js";import"./DjhyXAWM.js";import"./BtFwTo8r.js";import"./-McgzSt8.js";import"./CxL7XM5S.js";import"./DkGm0mVx.js";import"./Dae9l9X8.js";import"./CXYqlXVv.js";import"./3tzwFWSy.js";import"./CWYJKxYN.js";import"./B2VSf2nI.js";import"./D8qtllGy.js";import"./Cudb-hta.js";import"./Cu6wITbB.js";import"./-Wmyceoe.js";import"./PXbkGBwQ.js";import"./DA3gy1uR.js";import"./BcnXPBr1.js";const b={class:"privacy-page-bg"},y=d({__name:"privacy",setup(u){const i=v();return(h,a)=>{const t=s;return n(),l("div",b,[a[1]||(a[1]=r('<div class="privacy-content" data-v-60588c2b><div class="privacy-header" data-v-60588c2b><div class="privacy-header-top" data-v-60588c2b><img src="'+e+'" alt="logo" class="privacy-header-logo" data-v-60588c2b><div class="privacy-header-brand" data-v-60588c2b>凡图拉</div></div><div class="privacy-header-title" data-v-60588c2b>凡图拉平台隐私政策</div><div class="privacy-header-en" data-v-60588c2b>Ventura Privacy Policy</div><div class="privacy-header-desc" data-v-60588c2b>我们深知个人信息对您的重要性，并承诺依法收集、合理使用并保护您的信息安全</div></div><div class="privacy-body" data-v-60588c2b><div class="privacy-col privacy-col-cn privacy-col-cn-main" data-v-60588c2b><div class="privacy-overview-box privacy-overview-box-cn" data-v-60588c2b><div class="privacy-overview-title" data-v-60588c2b>隐私政策概览</div><div class="privacy-overview-desc" data-v-60588c2b>本政策适用于凡图拉平台提供的所有服务。我们深知个人信息对您的重要性，并致力于通过符合行业高标准的安全技术与管理机制，保护您的个人信息安全。本政策旨在详尽说明我们在您使用服务过程中如何收集、使用、存储及保护您的信息。</div></div><div class="privacy-spacer" style="height:20px;" data-v-60588c2b></div><div class="privacy-section-title blue-title with-line" data-v-60588c2b>一、我们如何收集与使用信息</div><div class="privacy-section-line" data-v-60588c2b></div><div class="privacy-section" data-v-60588c2b><div class="privacy-section-desc" data-v-60588c2b>1.1 为向您提供数字化权益服务协助（如账户管理、权益兑换记录），我们仅遵循“最小化原则”收集必要信息：</div><ul class="privacy-list blue-dot" data-v-60588c2b><li data-v-60588c2b>电子邮箱地址：用于创建唯一用户标识、账户安全验证及接收服务通知。</li><li data-v-60588c2b>服务交互日志：包括登录时间、操作记录、服务兑换流水，用于保障系统稳定运行及故障排查。</li><li data-v-60588c2b>设备及网络信息：匿名化的设备标识符与网络状态，用于反舞弊安全风控。</li></ul><div class="privacy-spacer" style="height:25px;" data-v-60588c2b></div><div class="privacy-section-highlight" data-v-60588c2b>1.2 本平台严格承诺不收集任何非必要的敏感个人信息，包括但不限于：</div><ul class="privacy-list blue-dot" data-v-60588c2b><li data-v-60588c2b>居民身份证号码、护照等任何法定身份证明文件</li><li data-v-60588c2b>个人生物识别信息（如面部识别特征、指纹、声纹）</li><li data-v-60588c2b>银行卡号、信用卡CVV码等金融支付敏感信息</li><li data-v-60588c2b>个人基因、健康医疗等特殊敏感数据</li></ul><div class="privacy-spacer" style="height:25px;" data-v-60588c2b></div><div class="privacy-section-desc" data-v-60588c2b>1.3 信息的合法使用场景：</div><ul class="privacy-list blue-dot" data-v-60588c2b><li data-v-60588c2b>为您提供账户安全管理、防范安全风险</li><li data-v-60588c2b>基于您的主动请求，提供权益查询、售后支持服务</li><li data-v-60588c2b>生成去标识化的统计数据，用于优化平台的数字化服务流程</li></ul></div><div class="privacy-spacer" style="height:25px;" data-v-60588c2b></div><div class="privacy-section-title blue-title with-line" data-v-60588c2b>二、Cookies 与同类技术的使用</div><div class="privacy-section-line" data-v-60588c2b></div><div class="privacy-section" data-v-60588c2b><div class="privacy-section-desc" data-v-60588c2b>2.1 为确保网站正常运转，我们会在您的计算机或移动设备上存储名为 Cookie 的小数据文件。Cookie 通常包含标识符、站点名称以及一些号码和字符。我们使用该技术主要为了：</div><ul class="privacy-list blue-dot" data-v-60588c2b><li data-v-60588c2b>维持您的登录状态，避免您重复执行已授权的操作</li><li data-v-60588c2b>保障数据安全性，排查异常登录行为</li><li data-v-60588c2b>分析服务使用情况，帮助我们需要改进服务内容</li></ul><div class="privacy-spacer" style="height:30px;" data-v-60588c2b></div><div class="privacy-section-desc" data-v-60588c2b>2.2 您可根据自己的偏好管理或删除 Cookie。您应当知晓，若禁用 Cookie，某些服务功能可能无法正常运作。</div></div><div class="privacy-spacer" style="height:60px;" data-v-60588c2b></div><div class="privacy-section-title blue-title with-line" data-v-60588c2b>三、信息的共享、披露与转让</div><div class="privacy-section-line" data-v-60588c2b></div><div class="privacy-section" data-v-60588c2b><span class="privacy-bold" data-v-60588c2b>3.1</span> 我们严格限制信息共享范围，仅在以下必要情况下： <ul class="privacy-list blue-dot" data-v-60588c2b><li data-v-60588c2b>获得您明确的单独同意或授权</li><li data-v-60588c2b>为完成权益兑换与交付所必需：仅向合作的数字化权益服务商提供必要的兑换标识信息</li><li data-v-60588c2b>依据法律法规或行政、司法机关的强制性要求</li></ul><div class="privacy-spacer" style="height:25px;" data-v-60588c2b></div><div class="privacy-highlight-box" data-v-60588c2b><span class="privacy-bold" data-v-60588c2b>3.2</span> 我们承诺绝不出售您的个人信息给任何第三方用于商业营销。 </div><div class="privacy-spacer" style="height:20px;" data-v-60588c2b></div><span class="privacy-bold" data-v-60588c2b>3.3</span> 如涉及到平台运营主体变更（如合并、重组），我们会要求新的主体继续受本隐私政策的约束，否则我们将要求该公司、组织重新向您征求授权同意。 </div><div class="privacy-spacer" style="height:40px;" data-v-60588c2b></div><div class="privacy-section-title blue-title with-line" data-v-60588c2b>四、您对个人信息的管理权</div><div class="privacy-section-line" data-v-60588c2b></div><div class="privacy-section" data-v-60588c2b><span class="privacy-bold" data-v-60588c2b>4.1</span> 您有权随时登录账户，查阅、更正您的基础注册信息。<br data-v-60588c2b><span class="privacy-bold" data-v-60588c2b>4.2</span> 在符合法律法规要求的前提下，您有权要求删除您的特定信息。<br data-v-60588c2b><span class="privacy-bold" data-v-60588c2b>4.3</span> 您可以随时申请注销账户。注销后，我们将停止为您提供产品或服务，并依据法律规定对您的个人信息进行匿名化处理或删除。 </div><div class="privacy-spacer" style="height:50px;" data-v-60588c2b></div><div class="privacy-section-title blue-title with-line" data-v-60588c2b>五、信息安全保障措施</div><div class="privacy-section-line" data-v-60588c2b></div><div class="privacy-section" data-v-60588c2b><span class="privacy-bold" data-v-60588c2b>5.1</span> 我们采用符合业界标准的安全防护措施，包括： <ul class="privacy-list blue-dot" data-v-60588c2b><li data-v-60588c2b>使用 SSL/TLS 加密技术传输数据，防止传输链路泄露</li><li data-v-60588c2b>建立严格的数据访问权限控制与多重身份认证机制</li><li data-v-60588c2b>部署定期的数据安全审计与网络漏洞扫描</li></ul><div class="privacy-spacer" style="height:25px;" data-v-60588c2b></div><div class="privacy-highlight-box" data-v-60588c2b><span class="privacy-bold" data-v-60588c2b>5.2</span> 您的信息将存储于中华人民共和国境内的安全服务器中，除非法律法规另有规定，我们不会向境外传输。 </div></div><div class="privacy-spacer" style="height:40px;" data-v-60588c2b></div><div class="privacy-section-title blue-title with-line" data-v-60588c2b>六、未成年人保护</div><div class="privacy-section-line" data-v-60588c2b></div><div class="privacy-section" data-v-60588c2b> 本平台仅面向 18 周岁及以上成年人提供服务。若您未满 18 周岁，请立即停止使用本平台。如果你是未成年人的监护人，且认为我们在不知情的情况下收集了未成年人的信息，请联系我们需要删除。 </div><div class="privacy-spacer" style="height:60px;" data-v-60588c2b></div><div class="privacy-section-title blue-title with-line" data-v-60588c2b>七、政策更新</div><div class="privacy-section-line" data-v-60588c2b></div><div class="privacy-section" data-v-60588c2b> 随着业务发展及法律法规变化，我们可能会修订本政策。所有变更将通过网站公告或邮件通知的方式告知。若您在政策更新后继续使用服务，即表示您已充分阅读、理解并接受更新后的政策内容。 </div><div class="privacy-spacer" style="height:55px;" data-v-60588c2b></div><div class="privacy-contact-card" data-v-60588c2b><div class="privacy-contact-title" data-v-60588c2b>联系我们</div><div class="privacy-contact-desc" data-v-60588c2b>如您对本隐私政策有任何疑问、投诉或建议，请通过以下方式联系数据安全专员：</div><div class="privacy-contact-mail" data-v-60588c2b>support@fantura.com</div><div class="privacy-contact-tip" data-v-60588c2b>我们将在收到您的请求后 15 个工作日内完成核查与处理</div></div><div class="privacy-spacer" style="height:15px;" data-v-60588c2b></div><div class="privacy-section-appendix" data-v-60588c2b><span class="privacy-appendix-title" data-v-60588c2b>附：条款效力说明</span><br data-v-60588c2b><span class="privacy-appendix-desc" data-v-60588c2b>本隐私政策提供英文翻译版本供参考，若中英文版本存在理解歧义，应以中文版表述为准。</span></div></div><div class="privacy-col privacy-col-en privacy-col-en-main" data-v-60588c2b><div class="privacy-overview-box privacy-overview-box-en" data-v-60588c2b><div class="privacy-overview-title" data-v-60588c2b>Ventura Privacy Policy</div><div class="privacy-overview-desc" data-v-60588c2b>Welcome to Ventura! We value your privacy and are committed to protecting your data through industry-standard security technologies and management mechanisms. This policy details how we collect, use, store, and protect your information during your use of our services.</div></div><div class="privacy-en-section-title" data-v-60588c2b>1. Information Collection and Use</div><div class="privacy-section-line" data-v-60588c2b></div><div class="privacy-section" data-v-60588c2b> 1.1 To provide you with digital equity service assistance (such as account management and redemption records), we collect only necessary information following the &quot;Minimization Principle&quot;: <ul class="privacy-list blue-dot" data-v-60588c2b><li data-v-60588c2b>Email Address: For unique user identification, account security verification, and service notifications.</li><li data-v-60588c2b>Service Logs: Including login timestamps, operation records, and service redemption flows for system stability.</li><li data-v-60588c2b>Device/Network Info: Anonymized device identifiers for security risk control.</li></ul><div class="privacy-en-highlight" data-v-60588c2b>1.2 We strictly DO NOT collect sensitive personal information, including:</div><ul class="privacy-list blue-dot" data-v-60588c2b><li data-v-60588c2b>ID cards, passports, or other legal identity documents</li><li data-v-60588c2b>Biometric data (facial features, fingerprints, etc.)</li><li data-v-60588c2b>Bank card numbers, CVV codes, or other financial payment secrets</li><li data-v-60588c2b>Genetic or health-related sensitive data</li></ul> 1.3 Legitimate Usage Scenarios: <ul class="privacy-list blue-dot" data-v-60588c2b><li data-v-60588c2b>Provide account security management and risk prevention</li><li data-v-60588c2b>Provide equity inquiry and after-sales support upon your request</li><li data-v-60588c2b>Generate de-identified statistics to optimize digital service processes</li></ul></div><div class="privacy-en-section-title" data-v-60588c2b>2. Cookies and Similar Technologies</div><div class="privacy-section-line" data-v-60588c2b></div><div class="privacy-section" data-v-60588c2b> 2.1 We use Cookies or similar local storage technologies to ensure the website functions properly. Cookies typically contain identifiers, site names, and some numbers/characters. We use this primarily to: <ul class="privacy-list blue-dot" data-v-60588c2b><li data-v-60588c2b>Maintain your login session status</li><li data-v-60588c2b>Ensure data security and detect abnormal login behaviors</li><li data-v-60588c2b>Analyze service usage to improve our offerings</li></ul> 2.2 You can manage or delete Cookies based on your preferences. Please note that disabling Cookies may affect some service functions. </div><div class="privacy-en-section-title" data-v-60588c2b>3. Information Sharing and Disclosure</div><div class="privacy-section-line" data-v-60588c2b></div><div class="privacy-section" data-v-60588c2b> 3.1 We strictly limit information sharing to necessary circumstances: <ul class="privacy-list blue-dot" data-v-60588c2b><li data-v-60588c2b>With your explicit separate consent</li><li data-v-60588c2b>Necessary for service fulfillment: Sharing only necessary redemption identifiers with equity service partners</li><li data-v-60588c2b>Compliance with laws, regulations, or mandatory government requests</li></ul><div class="privacy-en-highlight-box" data-v-60588c2b><span class="privacy-en-bold" data-v-60588c2b>3.2 We strictly promise NOT to sell your personal information to any third party.</span></div> 3.3 In the event of a merger or restructuring, we will require the new entity to continue to be bound by this policy, otherwise, we will ask them to seek your authorization again. </div><div class="privacy-en-section-title" data-v-60588c2b>4. Your Data Management Rights</div><div class="privacy-section-line" data-v-60588c2b></div><div class="privacy-section" data-v-60588c2b> 4.1 You have the right to access and correct your basic registration information.<br data-v-60588c2b> 4.2 You have the right to request deletion of specific information as permitted by law.<br data-v-60588c2b> 4.3 You can request account cancellation at any time. Upon cancellation, we will stop providing services and anonymize or delete your data according to laws. </div><div class="privacy-en-section-title" data-v-60588c2b>5. Information Security Measures</div><div class="privacy-section-line" data-v-60588c2b></div><div class="privacy-section" data-v-60588c2b> 5.1 We adopt industry-standard security measures, including: <ul class="privacy-list blue-dot" data-v-60588c2b><li data-v-60588c2b>SSL/TLS encryption for data transmission</li><li data-v-60588c2b>Strict data access controls and multi-factor authentication</li><li data-v-60588c2b>Regular security audits and vulnerability scanning</li></ul><div class="privacy-en-highlight-box" data-v-60588c2b><span class="privacy-en-bold" data-v-60588c2b>5.2 Your data is stored on secure servers within the PRC and will not be transferred cross-border unless required by law.</span></div></div><div class="privacy-en-section-title" data-v-60588c2b>6. Protection of Minors</div><div class="privacy-section-line" data-v-60588c2b></div><div class="privacy-section" data-v-60588c2b> This platform is intended for adults aged 18 and above. If you are under 18, please stop using this platform immediately. If you are a guardian and believe we collected a minor&#39;s data unknowingly, please contact us for deletion. </div><div class="privacy-en-section-title" data-v-60588c2b>7. Policy Updates</div><div class="privacy-section-line" data-v-60588c2b></div><div class="privacy-section" data-v-60588c2b> We may revise this policy as our business evolves. Changes will be notified via website announcements or emails. Continued use after updates implies acceptance of the revised policy. </div><div class="privacy-en-contact-card" data-v-60588c2b><div class="privacy-en-contact-title" data-v-60588c2b>Contact Us</div><div class="privacy-en-contact-desc" data-v-60588c2b>If you have questions or suggestions, please contact our Data Security Officer:</div><div class="privacy-en-contact-mail" data-v-60588c2b>support@fantura.com</div><div class="privacy-en-contact-tip" data-v-60588c2b>We will process your request within 15 working days</div></div><div class="privacy-en-appendix" data-v-60588c2b><span class="privacy-en-appendix-title" data-v-60588c2b>Appendix: Validity</span><br data-v-60588c2b><span class="privacy-en-appendix-desc" data-v-60588c2b>The English version is for reference only. In case of discrepancy, the Chinese version shall prevail.</span></div></div></div></div>',1)),o(t,{visible:c(i).showLogin,onClose:a[0]||(a[0]=m=>c(i).closeLogin())},null,8,["visible"])])}}}),R=p(y,[["__scopeId","data-v-60588c2b"]]);export{R as default};
